<template lang="en">
    <div>
        <loader :is-visible="isLoading"></loader>
        <section class="main-content">
            <div ref="hellp" id="divMaindealData">
                <div class="row">
                    <div class="col-md-12 padding-t_8">
                        <div class="theme-primary partition-full">
                            <span v-if="AddUserAvailability" class="p-name text-white">{{ $t('AddNewUserStatus') }}</span>
                            <span v-if="UpdateUserAvailability" class="p-name text-white">{{ $t('UpdateUserStatus') }}</span>
                            <span class="float-right">
                                <a href="javascript:;" class="p-action-btn text-white" :title="$t('BacktoList')" @click="Close">
                                    <em class="fa fa-angle-double-left pr-2" aria-hidden="true"></em>
                                    <br />{{ $t('BacktoList') }}
                                </a>
                            </span>
                        </div>
                    </div>
                </div>
                <div class="border p-3">
                    <Form ref="UserForm">
                        <dynamic-form ref="AddUser" lang="en" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    </Form>
                </div>
            </div>            
        </section>
    </div>
</template>

<script>
import DataService from "@/services/DataService";
export default {
    data() {
        return {
            isLoading: false,
            AddUserAvailability: true,
            UpdateUserAvailability: false,
            AvailabilityId: 0,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [
                {
                    layoutType: "four",
                    Data: [
                    {
                        astype: "TextField",
                        label: this.$t('Title'),
                        name: "Title",
                        value: "",
                        placeholder: this.$t('Title'),
                        validationRules: { "required": true, max: 100 },
                    },
                    {
                        astype: "SelectField",
                        label: this.$t('UserStatus'),
                        name: "UserStatus",
                        value: "",
                        visibility: true,
                        config: {
                            options: []
                        },
                        validationRules: { "required": true },
                    },
                    {
                        astype: "DateField",
                        label: this.$t('StartTime'),
                        name: "StartTime",
                        //value: new Date(),
                        visibility: true,
                        placeholder: this.$t('StartTime'),
                        config: {
                            mode: "time",
                                format: "hh:mm",
                                minuteIncrement: "5"
                            },
                        validationRules: { "required": true, max: 100 },
                    },
                    {
                        astype: "DateField",
                        label: this.$t('EndTime'),
                        name: "EndTime",
                        //value: new Date(),
                        visibility: true,
                        placeholder: this.$t('EndTime'),
                        config: {
                            mode: "time",
                                format: "hh:mm",
                                minuteIncrement: "5"
                            },
                        validationRules: { "required": true, max: 100 },
                    }]
                },
                {
                    layoutType: "four",
                    Data: [
                    {
                        astype: "DateField",
                        label: this.$t('StartDate'),
                        name: "StartDate",
                        //value: new Date(),
                        placeholder: "Enter Start Date",
                        config: {
                            options: [],
                            minDate: new Date()
                        },
                        validationRules: {
                            "required": true
                        },
                        visibility: true,
                    },
                    {
                        astype: "SelectField",
                        label: this.$t('Recurring'),
                        name: "Recurring",
                        value: "",
                        visibility: true,
                        config: {
                            options: []
                        },
                        validationRules: { "required": true, max: 100 },
                    }]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Close",
                    onClick: this.Close
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.AvailabilityId = this.$route.params.id;
        if (vm.AvailabilityId > 0) {
            vm.GetUserByAvailabilityId();
            vm.AddUserAvailability = false;
            vm.UpdateUserAvailability = true;
            vm.FormSchema[1].Data[1].visibility = false;
        }
        await vm.GetStatus()
        await vm.GetRecurring();
    },
    methods: {
        GetUserByAvailabilityId: async function () {
            var vm = this;
            var url = `AvailabilityId=${vm.AvailabilityId}`;
            await DataService.GetUserByAvailabilityId(url).then((response) => {
                vm.UserAvailabilityDetail = [];
                if (response.data && response.data.length > 0) {
                    vm.UserAvailabilityDetail = response.data;
                    vm.FormSchema[0].Data[0].value = vm.UserAvailabilityDetail[0].availability_title;
                    vm.FormSchema[0].Data[1].value = vm.UserAvailabilityDetail[0].availability_status_id;
                    vm.FormSchema[0].Data[2].value = vm.UserAvailabilityDetail[0].availability_start_time;
                    vm.FormSchema[0].Data[3].value = vm.UserAvailabilityDetail[0].availability_end_time;
                    vm.FormSchema[1].Data[0].value = vm.UserAvailabilityDetail[0].availability_start_date;
                }
            });
        },
        Close: function () {
            var vm = this;
            vm.$router.push('/UserAvailability/Index')
        },
        GetStatus: async function () {     
            var url =`statusType=AvalibilityNonavalibility&hasglobal=true&langCode=en`;
            await DataService.GetCommonStatusList(url).then((response)=>{ 
                if (response.data.length > 0 ){
                    response.data.forEach(element => {
                        if (element.STATUS == "Available" || element.STATUS == "Busy") {
                            let obj= {
                                name: element.STATUS,
                                value: element.STATUS_ID
                            }                            
                            this.FormSchema[0].Data[1].config.options.push(obj);
                        }
                    });
                }
                this.$refs.AddUser.UpdateKeyValue();
            });
        },
        GetRecurring: async function () {
            var url = `id=&moduleName=CRM&type=EVENT_RECURRING&search=&refId=`;
            await DataService.GetRecurring(url).then((response)=>{ 
                if (response.data != '' ){
                    response.data.forEach(itm => {
                        let obj= {
                            name: itm.name,
                            value: itm.value
                        }                            
                        this.FormSchema[1].Data[1].config.options.push(obj);
                    });
                }
                this.$refs.AddUser.UpdateKeyValue();
            });
        },
        onSubmit(formfields, val) {
            var vm = this;
            var jsonobj = {
                AvailabilityId: vm.AvailabilityId == null ? 0 : vm.AvailabilityId,
                AvailabilityTitle: formfields.Title,
                AvailabilityStatus: formfields.UserStatus, 
                AvailabilityStartDate: formfields.StartDate,       //vm.$options.filters.formatDate(formfields.StartDate),
                AvailabilityStartTime: formfields.StartTime,       //vm.$options.filters.formatTime(formfields.StartTime),
                AvailabilityEndTime: formfields.EndTime,           //vm.$options.filters.formatTime(formfields.EndTime),
                AvailabilityRecurringId: formfields.Recurring,          
            };
            var params = JSON.stringify(jsonobj);
            DataService.AddUpdateUserAvailability(params).then((response) => {
                if (response.status == 200) {
                    if (vm.AvailabilityId > 0) {
                        vm.ShowAlert(vm.$t("UpdatedSuccess", [vm.$t("UserAvailability")]), "success", true, vm.$t("Alert"));
                    }
                    else {
                        vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("UserAvailability")]), "success", true, vm.$t("Alert"));
                    }
                    vm.Close(); 
                }
                else {
                    vm.ShowAlert(vm.$t("AddedError", [vm.$t("UserAvailability")]), "failure", true, vm.$t("Alert"));
                    vm.Close();
                }
            });
        }
    }
}
</script>